// --- Input validation helpers ---
function validateId(id) {
  if (!Number.isInteger(id) || id < 1 || id > Number.MAX_SAFE_INTEGER) {
    throw new UserInputError(`Invalid user ID: ${id}. Must be a positive integer.`);
  }
  return id;
}

function validateIdArray(ids) {
  if (!Array.isArray(ids)) {
    throw new UserInputError('IDs must be provided as an array.');
  }
  if (ids.length === 0) {
    throw new UserInputError('IDs array must not be empty.');
  }
  if (ids.length > MAX_QUERY_IDS) {
    throw new UserInputError(`Cannot query more than ${MAX_QUERY_IDS} users at once. Received: ${ids.length}.`);
  }
  // Deduplicate and validate each ID
  const uniqueIds = [...new Set(ids)];
  return uniqueIds.map(validateId);
}

function validatePaginationInput(limit, offset) {
  if (!Number.isInteger(limit) || limit < 1 || limit > MAX_QUERY_IDS) {
    throw new UserInputError(`Limit must be an integer between 1 and ${MAX_QUERY_IDS}.`);
  }
  if (!Number.isInteger(offset) || offset < 0) {
    throw new UserInputError('Offset must be a non-negative integer.');
  }
}

function sanitizeStringInput(input, fieldName, maxLength = 255) {
  if (typeof input !== 'string') {
    throw new UserInputError(`${fieldName} must be a string.`);
  }
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    throw new UserInputError(`${fieldName} must not be empty.`);
  }
  if (trimmed.length > maxLength) {
    throw new UserInputError(`${fieldName} must not exceed ${maxLength} characters.`);
  }
  return trimmed;
}

function validateEmail(email) {
  const sanitized = sanitizeStringInput(email, 'Email', 254);
  // RFC 5322 simplified validation
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  if (!emailRegex.test(sanitized)) {
    throw new UserInputError('Invalid email format.');
  }
  return sanitized.toLowerCase();
}

function validateUsername(username) {
  const sanitized = sanitizeStringInput(username, 'Username', 50);
  const usernameRegex = /^[a-zA-Z0-9_-]+$/;
  if (!usernameRegex.test(sanitized)) {
    throw new UserInputError('Username may only contain alphanumeric characters, hyphens, and underscores.');
  }
  return sanitized;
}

const ALLOWED_ROLES = new Set(['user', 'moderator', 'admin']);

function validateRole(role) {
  const sanitized = sanitizeStringInput(role, 'Role', 20).toLowerCase();
  if (!ALLOWED_ROLES.has(sanitized)) {
    throw new UserInputError(`Invalid role. Allowed roles: ${[...ALLOWED_ROLES].join(', ')}.`);
  }
  return sanitized;
}

// --- Authorization helpers ---
function requireAuthentication(context) {
  if (!context.user) {
    throw new AuthenticationError('You must be authenticated to perform this action.');
  }
  return context.user;
}

function requireRole(context, allowedRoles) {
  const user = requireAuthentication(context);
  if (!allowedRoles.includes(user.role)) {
    throw new ForbiddenError('You do not have permission to perform this action.');
  }
  return user;
}

